	<script>function phGetPriceFormat($price) {
	var $negative = 0;
 	if ($price < 0) {
 		$negative = 1;
	}
	if ($negative == 1 ) {
 		$price = Math.abs($price);
 	}
 	$price = phNumberFormat($price, "", "", "");
	$price = $price + " " + "";
	if ($negative == 1) {
		return "- " + "" + $price + "";
	} else {
		return "" + $price + "";
	}
}
 </script>
